Unit test

Create a unit test to reproduce and verify the fix. This test includes ASCII and multi-byte UTF-8 words to make sure byte offsets are correct.

File: analysis/token/camelcase/camelcase_filter_test.go

```go
package camelcase

import (
	"testing"

	"github.com/blevesearch/bleve/v2/analysis"
)

func TestCamelCaseSplitASCII(t *testing.T) {
	filter := NewCamelCaseFilter()

	tok := &analysis.Token{
		Term:  []byte("camelCaseWord"),
		Start: 0,
		End:   len([]byte("camelCaseWord")),
	}

	out := filter.Filter(analysis.TokenStream{tok})

	if len(out) != 3 {
		t.Fatalf("expected 3 tokens, got %d", len(out))
	}
	want := []string{"camel", "Case", "Word"}
	got := []string{string(out[0].Term), string(out[1].Term), string(out[2].Term)}
	for i := range want {
		if got[i] != want[i] {
			t.Fatalf("token %d: expected %q got %q", i, want[i], got[i])
		}
	}

	// check byte offsets
	if out[0].Start != 0 || out[0].End != 5 {
		t.Fatalf("first token offsets wrong: %d-%d", out[0].Start, out[0].End)
	}
	if out[1].Start != 5 || out[1].End != 9 {
		t.Fatalf("second token offsets wrong: %d-%d", out[1].Start, out[1].End)
	}
	if out[2].Start != 9 || out[2].End != 13 {
		t.Fatalf("third token offsets wrong: %d-%d", out[2].Start, out[2].End)
	}
}

func TestCamelCaseSplitUTF8(t *testing.T) {
	filter := NewCamelCaseFilter()

	// "καταΛόγος" - starts with Greek lowercase runes, then uppercase Lambda, then "όγος"
	// Using a mixed-byte-length example ensures we track byte offsets, not rune offsets.
	input := "καταΛόγος" // each greek letter is 2 bytes in UTF-8 (mostly)
	b := []byte(input)
	tok := &analysis.Token{
		Term:  b,
		Start: 0,
		End:   len(b),
	}

	out := filter.Filter(analysis.TokenStream{tok})
	if len(out) < 2 {
		t.Fatalf("expected at least 2 tokens, got %d", len(out))
	}

	// check that the sum of segment lengths equals original length (byte-wise)
	total := 0
	for _, o := range out {
		total += (o.End - o.Start)
	}
	if total != len(b) {
		t.Fatalf("segments byte length sum %d != original %d", total, len(b))
	}

	// Check Start/End coverage
	if out[0].Start != 0 {
		t.Fatalf("first start expected 0 got %d", out[0].Start)
	}
	last := out[len(out)-1]
	if last.End != len(b) {
		t.Fatalf("last end expected %d got %d", len(b), last.End)
	}
}
```

How this fixes the problem

- The code iterates the original []byte with utf8.DecodeRune and explicitly tracks the byte offset (i).
- It uses byte offsets when creating new tokens (token.Start + byteOffset), so Start/End are always correct for UTF-8 input.
- The split logic uses rune classes (upper/lower/digit) with lookahead for the common acronym boundary rule (Upper+Upper+Lower -> split before the last Upper).
- A unit test verifies both ASCII and multi-byte UTF-8 cases; the byte offsets are asserted.

