func TestCamelCaseSplitASCII(t *testing.T) {
	filter := NewCamelCaseFilter()

	tok := &analysis.Token{
		Term:  []byte("camelCaseWord"),
		Start: 0,
		End:   len([]byte("camelCaseWord")),
	}

